/* Simple static dashboard for model analytics folders.
 *
 * Loads docs/manifest.json (generated by tools/build_manifest.py).
 */

const MANIFEST_URL = 'manifest.json';

const el = (id) => document.getElementById(id);

function setStatus(msg, isError = false) {
  const s = el('status');
  s.textContent = msg;
  s.style.color = isError ? '#ff8a8a' : '';
}

function basename(path) {
  const parts = path.split('/');
  return parts[parts.length - 1];
}

function prettyName(file) {
  // Turn acc_vs_temp_reasoning_topk_40.png into a nicer caption
  return file
    .replace(/\.[^.]+$/, '')
    .replace(/_/g, ' ')
    .trim();
}

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function parseCsv(text) {
  // Minimal CSV parser (supports quoted fields and escaped quotes "").
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const c = text[i];

    if (inQuotes) {
      if (c === '"') {
        const next = text[i + 1];
        if (next === '"') {
          field += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        field += c;
      }
      continue;
    }

    if (c === '"') {
      inQuotes = true;
      continue;
    }

    if (c === ',') {
      row.push(field);
      field = '';
      continue;
    }

    if (c === '\n') {
      row.push(field);
      field = '';
      rows.push(row);
      row = [];
      continue;
    }

    if (c === '\r') {
      // ignore (we'll handle \r\n via \n case)
      continue;
    }

    field += c;
  }

  // last cell
  if (field.length > 0 || row.length > 0) {
    row.push(field);
    rows.push(row);
  }

  // drop trailing empty row
  if (rows.length && rows[rows.length - 1].length === 1 && rows[rows.length - 1][0] === '') {
    rows.pop();
  }

  return rows;
}

function renderTable(container, csvText, maxRows = 80) {
  if (!csvText || !csvText.trim()) {
    container.innerHTML = '<div class="muted">(empty)</div>';
    return;
  }

  const rows = parseCsv(csvText);
  if (!rows.length) {
    container.innerHTML = '<div class="muted">(no rows)</div>';
    return;
  }

  const head = rows[0];
  const body = rows.slice(1, maxRows + 1);

  let html = '<table><thead><tr>';
  for (const h of head) html += `<th>${escapeHtml(h)}</th>`;
  html += '</tr></thead><tbody>';

  for (const r of body) {
    html += '<tr>';
    for (let i = 0; i < head.length; i++) {
      const val = r[i] ?? '';
      html += `<td>${escapeHtml(val)}</td>`;
    }
    html += '</tr>';
  }

  html += '</tbody></table>';

  if (rows.length - 1 > maxRows) {
    html += `<div class="muted" style="padding:8px 10px;">Showing first ${maxRows} rows of ${rows.length - 1}.</div>`;
  }

  container.innerHTML = html;
}

async function safeFetchText(url) {
  try {
    const r = await fetch(url, { cache: 'no-store' });
    if (!r.ok) return null;
    return await r.text();
  } catch {
    return null;
  }
}

let manifest = null;

function getSelectedModel() {
  const modelId = el('modelSelect').value;
  return (manifest?.models || []).find((m) => m.id === modelId) || null;
}

function getSelectedAgg(model) {
  if (!model) return null;
  const aggId = el('aggSelect').value;
  return (model.aggs || []).find((a) => a.id === aggId) || null;
}

function clearMetrics() {
  el('metricsOverall').innerHTML = '';
  el('metricsGlobal').innerHTML = '';
  el('methodRankings').textContent = '';
  el('runConfig').textContent = '';
}

function renderDownloads(agg) {
  const wrap = el('downloads');
  wrap.innerHTML = '';
  if (!agg || !agg.files || Object.keys(agg.files).length === 0) {
    wrap.innerHTML = '<span class="muted">No files found.</span>';
    return;
  }

  const keys = Object.keys(agg.files).sort();
  for (const k of keys) {
    const href = agg.files[k];
    const a = document.createElement('a');
    a.href = href;
    a.target = '_blank';
    a.rel = 'noreferrer';
    a.className = 'chip';
    a.textContent = k;
    wrap.appendChild(a);
  }
}

function renderPlots(agg) {
  const gallery = el('plots');
  const empty = el('plotsEmpty');
  gallery.innerHTML = '';
  empty.textContent = '';

  const plots = (agg?.plots || []).slice();
  if (!plots.length) {
    empty.textContent = 'No plot images found in plots/. (Expected: plots/*.png)';
    return;
  }

  for (const p of plots) {
    const div = document.createElement('div');
    div.className = 'thumb';

    const link = document.createElement('a');
    link.href = p;
    link.target = '_blank';
    link.rel = 'noreferrer';

    const img = document.createElement('img');
    img.loading = 'lazy';
    img.src = p;
    img.alt = basename(p);

    link.appendChild(img);

    const cap = document.createElement('div');
    cap.className = 'cap';
    cap.textContent = prettyName(basename(p));

    div.appendChild(link);
    div.appendChild(cap);
    gallery.appendChild(div);
  }
}

async function renderMetrics(agg) {
  clearMetrics();
  if (!agg) return;

  // CSV previews
  const overallPath = agg.files?.['metrics_overall.csv'];
  const globalPath = agg.files?.['metrics_global.csv'];

  if (overallPath) {
    const txt = await safeFetchText(overallPath);
    if (txt) renderTable(el('metricsOverall'), txt, 80);
    else el('metricsOverall').innerHTML = '<div class="muted">Could not load.</div>';
  } else {
    el('metricsOverall').innerHTML = '<div class="muted">(missing)</div>';
  }

  if (globalPath) {
    const txt = await safeFetchText(globalPath);
    if (txt) renderTable(el('metricsGlobal'), txt, 80);
    else el('metricsGlobal').innerHTML = '<div class="muted">Could not load.</div>';
  } else {
    el('metricsGlobal').innerHTML = '<div class="muted">(missing)</div>';
  }

  // Text previews
  const rankingsPath = agg.files?.['method_rankings.txt'];
  if (rankingsPath) {
    const txt = await safeFetchText(rankingsPath);
    el('methodRankings').textContent = txt ?? '(could not load)';
  } else {
    el('methodRankings').textContent = '(missing)';
  }

  const configPath = agg.files?.['run_config.json'];
  if (configPath) {
    const txt = await safeFetchText(configPath);
    el('runConfig').textContent = txt ?? '(could not load)';
  } else {
    el('runConfig').textContent = '(missing)';
  }
}

let histState = {
  topk: null,
  kind: null,
  temp: null,
  q: 0,
  minQ: 0,
  maxQ: 0,
  ext: 'png',
};

function _setOptions(selectEl, items, placeholder = '(none)') {
  selectEl.innerHTML = '';
  if (!items.length) {
    const opt = document.createElement('option');
    opt.value = '';
    opt.textContent = placeholder;
    selectEl.appendChild(opt);
    return;
  }

  for (const it of items) {
    const opt = document.createElement('option');
    opt.value = it;
    opt.textContent = it;
    selectEl.appendChild(opt);
  }
}

function refreshHistogramControls(agg) {
  const hist = agg?.histograms || {};

  const topks = Object.keys(hist).sort();
  _setOptions(el('histTopk'), topks, '(no histograms)');

  histState.topk = topks[0] || null;
  el('histTopk').value = histState.topk || '';

  const kinds = histState.topk ? Object.keys(hist[histState.topk] || {}).sort() : [];
  _setOptions(el('histKind'), kinds, '(none)');

  histState.kind = kinds[0] || null;
  el('histKind').value = histState.kind || '';

  const temps = (histState.topk && histState.kind)
    ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
    : [];
  _setOptions(el('histTemp'), temps, '(none)');

  histState.temp = temps[0] || null;
  el('histTemp').value = histState.temp || '';

  // Update range from selected
  syncHistogramRange(agg);
  updateHistogramImage(agg);
}

function syncHistogramRange(agg) {
  const hist = agg?.histograms || {};
  const info = (histState.topk && histState.kind && histState.temp)
    ? (((hist[histState.topk] || {})[histState.kind] || {})[histState.temp] || null)
    : null;

  if (!info) {
    histState.minQ = 0;
    histState.maxQ = 0;
    histState.ext = 'png';
    return;
  }

  histState.minQ = Number(info.min_q ?? 0);
  histState.maxQ = Number(info.max_q ?? 0);
  histState.ext = info.ext || 'png';

  // Clamp q
  const qEl = el('histQ');
  let q = Number(qEl.value || 0);
  if (Number.isNaN(q)) q = histState.minQ;
  q = Math.max(histState.minQ, Math.min(histState.maxQ, q));
  qEl.value = String(q);
  histState.q = q;

  el('histRange').textContent = info
    ? `q range: ${histState.minQ}..${histState.maxQ}`
    : '';
}

function updateHistogramImage(agg) {
  const empty = el('histEmpty');
  const img = el('histImg');
  const link = el('histLink');

  empty.textContent = '';

  if (!agg || !histState.topk || !histState.kind || !histState.temp) {
    img.style.display = 'none';
    link.href = '#';
    empty.textContent = 'No histograms available.';
    return;
  }

  const q = Number(el('histQ').value || 0);
  histState.q = q;

  const path = `${agg.base_path}/histograms/${histState.topk}/${histState.kind}/${histState.temp}/q_${q}.${histState.ext}`;

  img.style.display = 'block';
  img.src = path;
  img.alt = `q_${q}.${histState.ext}`;
  link.href = path;

  img.onerror = () => {
    img.style.display = 'none';
    empty.textContent = `Missing image: q_${q}.${histState.ext}`;
  };
}

function hookHistogramEvents() {
  el('histTopk').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.topk = el('histTopk').value;

    // Refresh downstream selects
    const hist = agg?.histograms || {};
    const kinds = histState.topk ? Object.keys(hist[histState.topk] || {}).sort() : [];
    _setOptions(el('histKind'), kinds, '(none)');
    histState.kind = kinds[0] || null;
    el('histKind').value = histState.kind || '';

    const temps = (histState.topk && histState.kind)
      ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
      : [];
    _setOptions(el('histTemp'), temps, '(none)');
    histState.temp = temps[0] || null;
    el('histTemp').value = histState.temp || '';

    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histKind').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.kind = el('histKind').value;

    const hist = agg?.histograms || {};
    const temps = (histState.topk && histState.kind)
      ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
      : [];
    _setOptions(el('histTemp'), temps, '(none)');
    histState.temp = temps[0] || null;
    el('histTemp').value = histState.temp || '';

    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histTemp').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.temp = el('histTemp').value;
    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histQ').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('prevQ').addEventListener('click', () => {
    const qEl = el('histQ');
    let q = Number(qEl.value || 0);
    q = Math.max(histState.minQ, q - 1);
    qEl.value = String(q);
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    updateHistogramImage(agg);
  });

  el('nextQ').addEventListener('click', () => {
    const qEl = el('histQ');
    let q = Number(qEl.value || 0);
    q = Math.min(histState.maxQ, q + 1);
    qEl.value = String(q);
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    updateHistogramImage(agg);
  });
}

function populateSelectors() {
  const modelSel = el('modelSelect');
  const aggSel = el('aggSelect');

  modelSel.innerHTML = '';
  aggSel.innerHTML = '';

  const models = manifest?.models || [];
  if (!models.length) {
    setStatus('No models found. Copy data into docs/models/<MODEL>/<RUN>/ and run tools/build_manifest.py', true);
    return;
  }

  for (const m of models) {
    const opt = document.createElement('option');
    opt.value = m.id;
    opt.textContent = m.label || m.id;
    modelSel.appendChild(opt);
  }

  modelSel.value = models[0].id;

  function rebuildAggOptions() {
    const model = getSelectedModel();
    aggSel.innerHTML = '';

    const aggs = model?.aggs || [];
    for (const a of aggs) {
      const opt = document.createElement('option');
      opt.value = a.id;
      opt.textContent = a.label || a.id;
      aggSel.appendChild(opt);
    }

    if (aggs.length) aggSel.value = aggs[0].id;
  }

  rebuildAggOptions();

  modelSel.addEventListener('change', async () => {
    rebuildAggOptions();
    await refreshView();
  });

  aggSel.addEventListener('change', async () => {
    await refreshView();
  });
}

async function refreshView() {
  const model = getSelectedModel();
  const agg = getSelectedAgg(model);

  if (!model || !agg) {
    setStatus('No data selected.', true);
    return;
  }

  setStatus(`Viewing ${model.id} / ${agg.id}`);

  renderPlots(agg);
  renderDownloads(agg);
  refreshHistogramControls(agg);
  await renderMetrics(agg);
}

async function loadManifest() {
  setStatus('Loading manifest…');
  try {
    const r = await fetch(MANIFEST_URL, { cache: 'no-store' });
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    manifest = await r.json();

    const ts = manifest.generated_at ? new Date(manifest.generated_at).toLocaleString() : '';
    el('manifestMeta').textContent = ts ? `(manifest: ${ts})` : '';

    populateSelectors();
    await refreshView();
  } catch (e) {
    console.error(e);
    setStatus('Failed to load manifest.json. Did you run tools/build_manifest.py?', true);
  }
}

el('reloadBtn').addEventListener('click', async () => {
  await loadManifest();
});

hookHistogramEvents();
loadManifest();
